+func TestHandleLifecycleSessionEnd_DeferredTurnEnd(t *testing.T) {
+	// Cannot use t.Parallel() because we use t.Chdir()
+	tmpDir := t.TempDir()
+	t.Chdir(tmpDir)
+
+	// Initialize git repo with a commit
+	setupGitRepoWithCommit(t, tmpDir)
+	paths.ClearWorktreeRootCache()
+
+	// Create .entire directory and session state in ACTIVE phase
+	if err := os.MkdirAll(paths.EntireDir, 0o755); err != nil {
+		t.Fatalf("Failed to create .entire: %v", err)
+	}
+
+	sessionID := "deferred-turnend-session"
+	sessionState := &strategy.SessionState{
+		SessionID: sessionID,
+	}
+	// Set phase to ACTIVE (simulates TurnEnd never firing)
+	sessionState.Phase = session.PhaseActive
+	if err := strategy.SaveSessionState(context.Background(), sessionState); err != nil {
+		t.Fatalf("Failed to save session state: %v", err)
+	}
+
+	ag := newMockAgent()
+	event := &agent.Event{
+		Type:       agent.SessionEnd,
+		SessionID:  sessionID,
+		SessionRef: "/nonexistent/transcript.jsonl", // transcript won't exist
+		Timestamp:  time.Now(),
+	}
+
+	// handleLifecycleSessionEnd should detect ACTIVE phase and dispatch
+	// a deferred turn-end. The deferred turn-end may fail (no file changes
+	// in this test), but the session should still be marked as ended.
+	err := handleLifecycleSessionEnd(context.Background(), ag, event)
+	if err != nil {
+		t.Errorf("handleLifecycleSessionEnd returned error: %v", err)
+	}
+
+	// Verify session was marked as ended
+	loadedState, loadErr := strategy.LoadSessionState(context.Background(), sessionID)
+	if loadErr != nil {
+		t.Fatalf("Failed to load session state: %v", loadErr)
+	}
+	if loadedState == nil {
+		t.Fatal("Session state is nil after session end")
+	}
+	if loadedState.EndedAt == nil {
+		t.Error("Session EndedAt should be set after session end")
+	}
+}
